import React from "react"
import { CardImage } from "./cardImage"
import { CardHeader } from "./cardHeader"
import { CardLinks } from "./cardLinks"
import { CardText } from "./cardText"
import "../styles/card.scss"
import PropTypes from 'prop-types'

export default class ProjectCard extends React.Component {
  render() {
    let p = this.props.project
    // compute link to use in child components: prefer fields.slug, but
    // strip leading `/portfolio` if present so links are at root: `/projectName`
    let raw = (p && p.fields && p.fields.slug) || p.slug || ''
    let link = String(raw || '')
    if (link.startsWith('/portfolio/')) {
      link = link.replace(/^\/portfolio\//, '/')
    }
    if (link === '' || link === '/') {
      link = '/'
    }

    return (
      <div className='col-sm-6 card__' style={{
        height: this.props.h,
      }}>
        <div className='card_body'>
          <CardImage data={{ media: p.media_pre, name: p.name, h: this.props.h, c: this.props.c }}
            link={link} />
          <CardHeader data={{ title: p.name, techs: p.techs }} />
          <CardLinks data={{ date: p.date, git: p.git_link, web: p.web_link, h: this.props.h }} />
          <CardText data={{ text: p.story, h: this.props.h }} link={link} />
        </div>
      </div>
    )
  }
}

ProjectCard.propTypes = {
  project: PropTypes.shape({
    fields: PropTypes.shape({
      slug: PropTypes.string,
    }),
    id: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    date: PropTypes.string,
    description: PropTypes.string,
    git_link: PropTypes.string,
    name: PropTypes.string,
    story: PropTypes.string,
    web_link: PropTypes.string,
    media: PropTypes.string,
    media_pre: PropTypes.string,
    techs: PropTypes.array,
  }).isRequired,
  h: PropTypes.number,
  c: PropTypes.object,
}

ProjectCard.defaultProps = {
  project: { fields: { slug: '/' }, name: '', media_pre: '', story: '' },
  h: 0,
  c: {},
}